// generar_213_test_rapido_resumen_clinico.js
// CHIQUI Entre Señales — Test rápidos positivos en el Resumen clínico
//
// Qué hace:
// En /vet, el Resumen clínico ahora incluye los test rápidos:
// - Para cada test, el resultado MÁS RECIENTE determina su estado (un
//   positivo antiguo que después salió negativo NO aparece como
//   positivo vigente -- misma regla que vacunas/antiparasitarios).
// - Cada positivo vigente se destaca:
//     "⚠️ Test rápido Ehrlichia: Positivo (hace 3 días)."
// - Y siempre se informa cuándo fue el último:
//     "🧪 Último test rápido hace 3 días." (+ "Sin resultados
//     positivos." si todo está negativo)
//
// Solo reescribe app/vet/page.tsx. No hay SQL.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_213_test_rapido_resumen_clinico.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/vet/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 1 archivo escrito correctamente.')
  console.log('No hay SQL esta vez. Puedes hacer git add / commit / push directo.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
